import { useState } from "react";

export default function UserCard() {
  const [user, setUser] = useState({ name: "Alice", role: "viewer" });

  function promoteToAdmin() {
    user.role = "admin";   // ← bug: mutates the object directly
    setUser(user);         // same reference — React sees no change
  }

  return (
    <div>
      <p>Name: {user.name}</p>
      <p>Role: {user.role}</p>
      <button onClick={promoteToAdmin}>Promote to Admin</button>
    </div>
  );
}

